namespace sv_201406150101468d9ef3ae95fd3f2631.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@if (Reactions is { Count: > 0 })
{
    <div class="reaction-bar">
        @foreach (var reaction in Reactions)
        {
            <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync(reaction.Emoji)"
                    title="@string.Join(", ", reaction.Users)">
                <span>@reaction.Emoji</span>
                <span class="reaction-count">@reaction.Users.Count</span>
            </button>
        }
    </div>
}

@code {
    [Parameter, EditorRequired] public List<Reaction> Reactions { get; set; } = [];
    [Parameter] public EventCallback<string> OnReact { get; set; }
}

@if (IsVisible)
{
    <div class="emoji-picker">
        @foreach (var emoji in _emojis)
        {
            <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
        }
    </div>
}

@code {
    [Parameter] public bool IsVisible { get; set; }
    [Parameter] public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = ["👍", "❤️", "😂", "😮", "😢", "🎉"];

    private async Task SelectEmoji(string emoji)
    {
        await OnEmojiSelected.InvokeAsync(emoji);
    }
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-list" @ref="_scrollContainer">
    @if (HasMore)
    {
        <div @ref="_sentinel" class="load-more-sentinel">
            @if (_loadingMore)
            {
                <span class="loading-indicator">Loading older messages…</span>
            }
        </div>
    }

    @foreach (var message in Messages)
    {
        <MessageBubble Message="message"
                       ThreadSummary="GetThreadSummary(message.Id)"
                       OnOpenThread="OnOpenThread"
                       OnReact="OnReact" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference _scrollContainer;
    private ElementReference _sentinel;
    private IJSObjectReference? _module;
    private DotNetObjectReference<MessageList>? _selfRef;
    private bool _loadingMore;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-201406150101468d9ef3ae95fd3f2631/Components/Chat/MessageList.razor.js");
            _selfRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("observeSentinel", _sentinel, _selfRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_loadingMore || !HasMore) return;
        _loadingMore = true;
        StateHasChanged();
        await OnLoadMore.InvokeAsync();
        _loadingMore = false;
        StateHasChanged();
    }

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.GetValueOrDefault(messageId);

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try { await _module.InvokeVoidAsync("disconnect"); }
            catch (JSDisconnectedException) { }
            await _module.DisposeAsync();
        }
        _selfRef?.Dispose();
    }
}

let observer = null;

export function observeSentinel(sentinel, dotNetRef) {
    if (observer) observer.disconnect();
    if (!sentinel) return;

    observer = new IntersectionObserver(entries => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetRef.invokeMethodAsync('OnSentinelVisible');
            }
        }
    }, { threshold: 0.1 });

    observer.observe(sentinel);
}

export function disconnect() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

@if (CurrentChannel is not null)
{
    <div class="message-area">
        <div class="message-area-header">
            <h2># @CurrentChannel.Name</h2>
            <p>@CurrentChannel.Description</p>
        </div>

        <MessageList Messages="Messages"
                     ThreadSummaries="ThreadSummaries"
                     HasMore="HasMore"
                     OnLoadMore="OnLoadMore"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />

        <MessageInput Placeholder="@($"Message #{CurrentChannel.Name}")"
                      ButtonText="Send"
                      OnSubmit="OnSendMessage" />
    </div>
}
else
{
    <div class="message-area empty-state">
        <p>Select a channel to start chatting</p>
    </div>
}

@code {
    [Parameter] public Channel? CurrentChannel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
}

@if (IsOpen && RootMessage is not null)
{
    <div class="thread-panel">
        <div class="thread-header">
            <h3>Thread</h3>
            <button class="close-btn" @onclick="OnClose">✕</button>
        </div>

        <div class="thread-root-message">
            <span class="message-author">@RootMessage.Author</span>
            <p class="message-content">@RootMessage.Content</p>
        </div>

        <div class="thread-replies">
            @foreach (var reply in ThreadMessages)
            {
                <div class="thread-reply">
                    <div class="message-header">
                        <span class="message-author">@reply.Author</span>
                        <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="message-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonText="Reply"
                      OnSubmit="OnSendReply" />
    </div>
}

@code {
    [Parameter] public bool IsOpen { get; set; }
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

