toolArgs.file_text:
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-list" @ref="_scrollContainer">
    @if (HasMore)
    {
        <div @ref="_sentinel" class="load-more-sentinel">
            @if (_loadingMore)
            {
                <span class="loading-indicator">Loading older messages…</span>
            }
        </div>
    }

    @foreach (var message in Messages)
    {
        <MessageBubble Message="message"
                       ThreadSummary="GetThreadSummary(message.Id)"
                       OnOpenThread="OnOpenThread"
                       OnReact="OnReact" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference _scrollContainer;
    private ElementReference _sentinel;
    private IJSObjectReference? _module;
    private DotNetObjectReference<MessageList>? _selfRef;
    private bool _loadingMore;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-201406150101468d9ef3ae95fd3f2631/Components/Chat/MessageList.razor.js");
            _selfRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("observeSentinel", _sentinel, _selfRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_loadingMore || !HasMore) return;
        _loadingMore = true;
        StateHasChanged();
        await OnLoadMore.InvokeAsync();
        _loadingMore = false;
        StateHasChanged();
    }

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.GetValueOrDefault(messageId);

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try { await _module.InvokeVoidAsync("disconnect"); }
            catch (JSDisconnectedException) { }
            await _module.DisposeAsync();
        }
        _selfRef?.Dispose();
    }
}

