{"file_text": "@page "/chat"
@attribute [RenderModeInteractiveServer]
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelList Channels="_channels"
                 SelectedChannelId="_selectedChannelId"
                 OnChannelSelected="SelectChannel" />

    <div class="chat-main @(_threadOpen ? "thread-open" : "")">
        <MessageArea CurrentChannel="_currentChannel"
                     Messages="_messages"
                     ThreadSummaries="_threadSummaries"
                     HasMore="_hasMore"
                     OnLoadMore="LoadOlderMessages"
                     OnSendMessage="SendMessage"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction" />
    </div>

    @if (_threadOpen)
    {
        <ThreadPanel IsOpen="_threadOpen"
                     RootMessage="_threadRootMessage"
                     ThreadMessages="_threadMessages"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private int? _selectedChannelId;
    private Channel? _currentChannel;
    private List<Message> _messages = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = [];
    private bool _hasMore = true;

    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadMessages = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _currentChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = [];
        _threadSummaries = [];
        _hasMore = true;
        CloseThread();

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        _hasMore = messages.Count >= PageSize;
        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);
        UpdateChannelUnread(channelId);
    }

    private async Task LoadOlderMessages()
    {
        if (_selectedChannelId is null) return;
        var older = await ChatService.GetMessagesAsync(_selectedChannelId.Value, _messages.Count, PageSize);
        if (older.Count < PageSize) _hasMore = false;
        _messages.InsertRange(0, older);
        BuildThreadSummaries();
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannelId is null) return;
        var message = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, null);
        _messages.Add(message);
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;

        if (_threadMessages.Count > 0)
        {
            _threadSummaries[rootMessageId] = new ThreadSummary(
                rootMessageId,
                _threadMessages.Count,
                _threadMessages[^1].SentAt);
        }
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_selectedChannelId is null || _threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, _threadRootMessage.Id);
        _threadMessages.Add(reply);

        _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
            _threadRootMessage.Id,
            _threadMessages.Count,
            reply.SentAt);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
    }

    private void BuildThreadSummaries()
    {
        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            if (!_threadSummaries.ContainsKey(group.Key))
            {
                _threadSummaries[group.Key] = new ThreadSummary(
                    group.Key,
                    group.Count(),
                    group.Max(m => m.SentAt));
            }
        }
    }

    private void UpdateChannelUnread(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = _channels[idx];
            _channels[idx] = ch with { UnreadCount = 0 };
        }
    }
}
