toolArgs.file_text:
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* ----- Sidebar ----- */
::deep .channel-list {
    width: 20%;
    min-width: 200px;
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    overflow-y: auto;
}

::deep .channel-list-title {
    padding: 16px;
    margin: 0;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #8e9297;
    border-bottom: 1px solid #40444b;
}

::deep .channel-list-items {
    flex: 1;
    overflow-y: auto;
}

::deep .channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background 0.15s;
}

::deep .channel-item:hover {
    background: #34373c;
}

::deep .channel-item.active {
    background: #393c43;
    border-left-color: #5865f2;
}

::deep .channel-header-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

::deep .unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

::deep .channel-desc {
    font-size: 0.78rem;
    color: #72767d;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ----- Main message area ----- */
.chat-main {
    flex: 1;
    min-width: 0;
    display: flex;
}

.chat-main.thread-open {
    /* shrinks to ~55% when thread is open */
}

::deep .message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #36393f;
    color: #dcddde;
    min-width: 0;
}

::deep .message-area.empty-state {
    justify-content: center;
    align-items: center;
}

::deep .message-area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #40444b;
    flex-shrink: 0;
}

::deep .message-area-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

::deep .message-area-header p {
    margin: 2px 0 0;
    font-size: 0.82rem;
    color: #8e9297;
}

/* ----- Message list ----- */
::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

::deep .load-more-sentinel {
    text-align: center;
    padding: 8px 0;
    min-height: 1px;
}

::deep .loading-indicator {
    color: #8e9297;
    font-size: 0.85rem;
}

/* ----- Message bubble ----- */
::deep .message-bubble {
    padding: 6px 10px;
    border-radius: 6px;
    position: relative;
    transition: background 0.1s;
}

::deep .message-bubble:hover {
    background: #32353b;
}

::deep .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

::deep .message-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.92rem;
}

::deep .message-time {
    font-size: 0.75rem;
    color: #72767d;
}

::deep .message-content {
    margin-top: 2px;
    line-height: 1.4;
    word-break: break-word;
}

::deep .thread-link {
    background: none;
    border: none;
    color: #5865f2;
    font-size: 0.82rem;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 4px;
    font-weight: 500;
}

::deep .thread-link:hover {
    text-decoration: underline;
}

::deep .message-actions {
    position: absolute;
    top: -10px;
    right: 10px;
    display: flex;
    gap: 4px;
    background: #2f3136;
    border: 1px solid #40444b;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 6px rgba(0,0,0,0.2);
}

::deep .action-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 0.78rem;
    padding: 4px 8px;
    border-radius: 4px;
    cursor: pointer;
    white-space: nowrap;
}

::deep .action-btn:hover {
    background: #40444b;
    color: #fff;
}

/* ----- Message input ----- */
::deep .message-input {
    display: flex;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #40444b;
    flex-shrink: 0;
}

::deep .message-input textarea {
    flex: 1;
    resize: none;
    border: none;
    border-radius: 8px;
    padding: 10px 14px;
    background: #40444b;
    color: #dcddde;
    font-size: 0.92rem;
    font-family: inherit;
    outline: none;
}

::deep .message-input textarea::placeholder {
    color: #72767d;
}

::deep .send-btn {
    padding: 8px 20px;
    background: #5865f2;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    align-self: flex-end;
}

::deep .send-btn:hover {
    background: #4752c4;
}

::deep .send-btn:disabled {
    background: #4752c4;
    opacity: 0.5;
    cursor: not-allowed;
}

/* ----- Thread panel ----- */
::deep .thread-panel {
    width: 25%;
    min-width: 280px;
    background: #2f3136;
    color: #dcddde;
    border-left: 1px solid #40444b;
    display: flex;
    flex-direction: column;
}

::deep .thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #40444b;
    flex-shrink: 0;
}

::deep .thread-header h3 {
    margin: 0;
    font-size: 1rem;
    color: #fff;
}

::deep .close-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
}

::deep .close-btn:hover {
    background: #40444b;
    color: #fff;
}

::deep .thread-root-message {
    padding: 12px 16px;
    border-bottom: 1px solid #40444b;
    background: #36393f;
    flex-shrink: 0;
}

::deep .thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
    display: flex;
    flex-direction: column;
    gap: 8px;
}

::deep .thread-reply {
    padding: 6px 0;
}

